"use client";

import * as React from "react";
import { useReducedMotion } from "motion/react";
import * as THREE from "three";

import { cn } from "@/lib/utils";
import { damp, supportsWebGL, useHydrated } from "@/components/experience/experience-runtime";

export type VolumetricLightBeam = { x: number; width?: number; angle?: number; color?: THREE.ColorRepresentation; intensity?: number };

export type VolumetricLightStageProps = Omit<React.ComponentProps<"section">, "children"> & {
  label: string;
  src: string;
  alt: string;
  beams?: VolumetricLightBeam[];
  density?: number;
  haze?: number;
  speed?: number;
  pointerStrength?: number;
  maxDpr?: number;
  children?: React.ReactNode;
  fallback?: React.ReactNode;
  canvasClassName?: string;
};

const VERTEX = /* glsl */ `varying vec2 vUv; void main(){vUv=uv;gl_Position=vec4(position,1.);}`;
const FRAGMENT = /* glsl */ `
  precision highp float;
  varying vec2 vUv;
  uniform sampler2D uTexture;
  uniform vec2 uResolution;
  uniform vec2 uImageSize;
  uniform vec2 uPointer;
  uniform float uTime;
  uniform float uDensity;
  uniform float uHaze;
  uniform vec3 uBeamColor[3];
  uniform vec3 uBeamData[3];
  float hash(vec2 p){p=fract(p*vec2(123.34,456.21));p+=dot(p,p+45.32);return fract(p.x*p.y);}
  float noise(vec2 p){vec2 i=floor(p),f=fract(p);f=f*f*(3.-2.*f);return mix(mix(hash(i),hash(i+vec2(1,0)),f.x),mix(hash(i+vec2(0,1)),hash(i+1.),f.x),f.y);}
  vec2 coverUv(vec2 uv){float a=uResolution.x/max(1.,uResolution.y),b=uImageSize.x/max(1.,uImageSize.y);vec2 r=vec2(min(a/b,1.),min(b/a,1.));return(uv-.5)*r+.5;}
  void main(){
    vec2 uv=vUv; vec3 base=texture2D(uTexture,coverUv(uv)).rgb;
    float mist=noise(uv*5.+vec2(uTime*.025,-uTime*.018))*uHaze;
    vec3 light=vec3(0.);
    for(int i=0;i<3;i++){
      float x=uBeamData[i].x+(uv.y-.5)*uBeamData[i].z;
      float width=max(.015,uBeamData[i].y)*(1.15-uv.y*.4);
      float shaft=exp(-pow(abs(uv.x-x)/width,2.))*smoothstep(.02,.42,1.-uv.y);
      float breakup=.65+.35*noise(vec2(uv.x*11.+float(i)*3.,uv.y*5.-uTime*.035));
      light+=uBeamColor[i]*shaft*breakup*uDensity;
    }
    float pointerGlow=exp(-length((uv-uPointer)*vec2(uResolution.x/max(1.,uResolution.y),1.))*4.2)*.12;
    vec3 color=base*(.78+mist*.24)+light+pointerGlow*mix(uBeamColor[0],uBeamColor[1],.5);
    color=1.-exp(-color*1.08);
    gl_FragColor=vec4(color,1.);
  }
`;
const DEFAULT_BEAMS: VolumetricLightBeam[] = [
  { x: .25, width: .12, angle: .18, color: "#ffd6a5", intensity: 1 },
  { x: .58, width: .16, angle: -.12, color: "#a5ddff", intensity: .85 },
  { x: .82, width: .09, angle: -.22, color: "#d6b6ff", intensity: .65 },
];

/** Image-backed procedural light shafts with bounded pointer influence. */
export function VolumetricLightStage({
  alt,
  beams = DEFAULT_BEAMS,
  canvasClassName,
  children,
  className,
  density = .72,
  fallback,
  haze = .55,
  label,
  maxDpr = 1.6,
  pointerStrength = .35,
  speed = 1,
  src,
  onPointerLeave,
  onPointerMove,
  ...props
}: VolumetricLightStageProps) {
  const rootRef = React.useRef<HTMLElement>(null);
  const canvasRef = React.useRef<HTMLCanvasElement>(null);
  const activeRef = React.useRef(true);
  const pointerRef = React.useRef({ x: .5, y: .5 });
  const targetRef = React.useRef({ x: .5, y: .5 });
  const hydrated = useHydrated();
  const reducedMotion = useReducedMotion();
  const staticMode = hydrated && Boolean(reducedMotion);
  const [ready, setReady] = React.useState(false);
  const [failed, setFailed] = React.useState(false);
  const beamSignature = JSON.stringify(beams);
  React.useEffect(() => {
    const root = rootRef.current, canvas = canvasRef.current;
    if (!root || !canvas || staticMode) return;
    if (!supportsWebGL()) { const timer = window.setTimeout(() => setFailed(true), 0); return () => window.clearTimeout(timer); }
    let disposed = false, frame = 0, elapsed = 0, previous = performance.now();
    let texture: THREE.Texture | null = null;
    const renderer = new THREE.WebGLRenderer({ canvas, antialias: false, alpha: false, powerPreference: "high-performance" });
    renderer.outputColorSpace = THREE.SRGBColorSpace;
    renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, maxDpr));
    const scene = new THREE.Scene(), camera = new THREE.Camera(), geometry = new THREE.PlaneGeometry(2, 2);
    const normalized = [0, 1, 2].map((index) => beams[index] ?? { x: .5, width: 0, angle: 0, color: "#000000", intensity: 0 });
    const uniforms = {
      uTexture: { value: new THREE.Texture() }, uResolution: { value: new THREE.Vector2(1, 1) }, uImageSize: { value: new THREE.Vector2(1, 1) },
      uPointer: { value: new THREE.Vector2(.5, .5) }, uTime: { value: 0 }, uDensity: { value: density }, uHaze: { value: haze },
      uBeamColor: { value: normalized.map((beam) => new THREE.Color(beam.color ?? "#ffffff").multiplyScalar(beam.intensity ?? 1)) },
      uBeamData: { value: normalized.map((beam) => new THREE.Vector3(beam.x, beam.width ?? .12, beam.angle ?? 0)) },
    };
    const material = new THREE.ShaderMaterial({ vertexShader: VERTEX, fragmentShader: FRAGMENT, uniforms, depthTest: false, depthWrite: false });
    scene.add(new THREE.Mesh(geometry, material));
    const resize = () => { const width = Math.max(1, root.clientWidth), height = Math.max(1, root.clientHeight); renderer.setSize(width, height, false); uniforms.uResolution.value.set(width, height); renderer.render(scene, camera); };
    const resizeObserver = new ResizeObserver(resize); resizeObserver.observe(root);
    const intersectionObserver = new IntersectionObserver(([entry]) => { activeRef.current = Boolean(entry?.isIntersecting); }, { rootMargin: "20% 0px" }); intersectionObserver.observe(root);
    const contextLost = (event: Event) => { event.preventDefault(); if (!disposed) setFailed(true); }; canvas.addEventListener("webglcontextlost", contextLost);
    const render = (time: number) => { if (disposed) return; const delta = Math.min(.05, Math.max(.001, (time - previous) / 1000)); previous = time; if (activeRef.current && document.visibilityState === "visible") { elapsed += delta * speed; pointerRef.current.x = damp(pointerRef.current.x, targetRef.current.x, 6, delta); pointerRef.current.y = damp(pointerRef.current.y, targetRef.current.y, 6, delta); uniforms.uTime.value = elapsed; uniforms.uPointer.value.set(pointerRef.current.x, pointerRef.current.y); renderer.render(scene, camera); } frame = requestAnimationFrame(render); };
    new THREE.TextureLoader().load(src, (loaded) => { if (disposed) { loaded.dispose(); return; } texture = loaded; texture.colorSpace = THREE.SRGBColorSpace; const image = loaded.image as { width?: number; height?: number }; uniforms.uTexture.value = loaded; uniforms.uImageSize.value.set(image.width ?? 1, image.height ?? 1); resize(); setReady(true); frame = requestAnimationFrame(render); }, undefined, () => { if (!disposed) setFailed(true); });
    return () => { disposed = true; cancelAnimationFrame(frame); resizeObserver.disconnect(); intersectionObserver.disconnect(); canvas.removeEventListener("webglcontextlost", contextLost); texture?.dispose(); geometry.dispose(); material.dispose(); renderer.dispose(); };
  // beamSignature intentionally captures the serializable beam contract.
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [beamSignature, density, haze, maxDpr, speed, src, staticMode]);
  const handlePointerMove = (event: React.PointerEvent<HTMLElement>) => { if (event.pointerType !== "touch") { const rect = event.currentTarget.getBoundingClientRect(); const x = (event.clientX - rect.left) / Math.max(1, rect.width); const y = 1 - (event.clientY - rect.top) / Math.max(1, rect.height); targetRef.current = { x: .5 + (x - .5) * pointerStrength, y: .5 + (y - .5) * pointerStrength }; } onPointerMove?.(event); };
  const handlePointerLeave = (event: React.PointerEvent<HTMLElement>) => { targetRef.current = { x: .5, y: .5 }; onPointerLeave?.(event); };
  const posterStyle = { backgroundImage: `url("${src.replaceAll('"', '%22')}")` };
  return <section ref={rootRef} aria-label={label} data-volumetric-light data-ready={ready || undefined} className={cn("relative isolate overflow-hidden bg-black", className)} onPointerMove={handlePointerMove} onPointerLeave={handlePointerLeave} {...props}><span className="sr-only">{alt}</span><div aria-hidden className={cn("absolute inset-0 -z-20 bg-cover bg-center", ready && !failed && !staticMode ? "opacity-0" : "opacity-100")} style={posterStyle} /><canvas ref={canvasRef} aria-hidden className={cn("absolute inset-0 -z-10 size-full transition-opacity duration-500", ready && !failed && !staticMode ? "opacity-100" : "opacity-0", canvasClassName)} />{(failed || staticMode) && fallback ? <div className="absolute inset-0 -z-10">{fallback}</div> : null}{children}</section>;
}

"use client";

import * as React from "react";

const subscribeToHydration = () => () => undefined;

export function useHydrated() {
  return React.useSyncExternalStore(subscribeToHydration, () => true, () => false);
}

export function useMediaQuery(query: string, serverValue = false) {
  const subscribe = React.useCallback(
    (onChange: () => void) => {
      const media = window.matchMedia(query);
      media.addEventListener("change", onChange);
      return () => media.removeEventListener("change", onChange);
    },
    [query],
  );
  const getSnapshot = React.useCallback(() => window.matchMedia(query).matches, [query]);
  return React.useSyncExternalStore(subscribe, getSnapshot, () => serverValue);
}

/**
 * Hydration-safe reduced-motion preference: false on the server and during
 * hydration, then live. Replaces the repeated `mounted && useReducedMotion()`
 * pattern.
 */
export function usePrefersReducedMotion() {
  return useMediaQuery("(prefers-reduced-motion: reduce)");
}

/** True on touch-first devices; use to swap pointer effects for static or rail modes. */
export function useCoarsePointer() {
  return useMediaQuery("(pointer: coarse)");
}

/** True only when a hover-capable precise pointer is present. */
export function useFinePointer() {
  return useMediaQuery("(hover: hover) and (pointer: fine)");
}

export function clamp01(value: number) {
  return Math.min(1, Math.max(0, value));
}

export function mix(from: number, to: number, amount: number) {
  return from + (to - from) * amount;
}

export function damp(current: number, target: number, smoothing: number, deltaSeconds: number) {
  return mix(current, target, 1 - Math.exp(-Math.max(0.01, smoothing) * deltaSeconds));
}

/** Returns the frames sorted by `at`, reusing the input when it is already ordered. */
export function sortKeyframes<T extends { at: number }>(frames: T[]): T[] {
  for (let index = 1; index < frames.length; index += 1) {
    if (frames[index - 1]!.at > frames[index]!.at) {
      return [...frames].sort((left, right) => left.at - right.at);
    }
  }
  return frames;
}

export function resolveKeyframes<T extends { at: number }>(
  frames: T[],
  progress: number,
): { from: T; to: T; mix: number } {
  if (frames.length === 0) throw new Error("Experience keyframes cannot be empty.");
  const sorted = sortKeyframes(frames);
  if (progress <= sorted[0]!.at) return { from: sorted[0]!, to: sorted[0]!, mix: 0 };
  for (let index = 0; index < sorted.length - 1; index += 1) {
    const from = sorted[index]!;
    const to = sorted[index + 1]!;
    if (progress <= to.at) {
      const span = Math.max(0.0001, to.at - from.at);
      return { from, to, mix: clamp01((progress - from.at) / span) };
    }
  }
  const final = sorted.at(-1)!;
  return { from: final, to: final, mix: 0 };
}

export function supportsWebGL() {
  try {
    const canvas = document.createElement("canvas");
    return Boolean(
      canvas.getContext("webgl2", { failIfMajorPerformanceCaveat: true })
      || canvas.getContext("webgl", { failIfMajorPerformanceCaveat: true }),
    );
  } catch {
    return false;
  }
}
